// famililook-shared/src/rewards/CelebrationBurst.jsx
// Unified confetti + haptic component. Three tiers per UPL review (2026-04-18).
// Replaces desktop2 custom Canvas confetti and desktop6 canvas-confetti calls.

import React, { useEffect, useRef } from 'react'
import { pattern } from '../theme/haptics.js'
import { confetti as confettiPalettes } from '../theme/dopamine.js'

/**
 * @prop {number} score - The numeric score that triggered this (0-100)
 * @prop {number} threshold - Minimum score to trigger (default 70, UPL-approved)
 * @prop {string} chemistryLabel - Optional, selects chemistry-specific confetti palette
 * @prop {boolean} active - Set to true to fire, false to reset
 */
export function CelebrationBurst({ score, threshold = 70, chemistryLabel, active }) {
  const firedRef = useRef(false)

  useEffect(() => {
    if (!active || score < threshold) {
      firedRef.current = false
      return
    }

    if (firedRef.current) return
    firedRef.current = true

    // Determine tier (UPL three-tier system)
    let particleCount, spread, bursts
    if (score >= 90) {
      // Full — peak celebration
      particleCount = 150
      spread = 90
      bursts = 2
    } else if (score >= 80) {
      // Light — clear celebration
      particleCount = 80
      spread = 60
      bursts = 1
    } else {
      // Subtle — acknowledgement (70-79)
      particleCount = 40
      spread = 45
      bursts = 1
    }

    // Select palette
    const colors = (chemistryLabel && confettiPalettes.chemistry[chemistryLabel])
      || confettiPalettes.standard

    // Fire confetti
    fireConfetti({ particleCount, spread, colors, bursts })

    // Haptic
    pattern.celebration()
  }, [active, score, threshold, chemistryLabel])

  return null // visual-only side effect component
}

async function fireConfetti({ particleCount, spread, colors, bursts }) {
  try {
    const { default: confetti } = await import('canvas-confetti')

    const base = {
      particleCount,
      spread,
      colors,
      origin: { y: 0.6 },
      disableForReducedMotion: true,
    }

    confetti(base)

    if (bursts >= 2) {
      setTimeout(() => confetti({ ...base, origin: { y: 0.5 } }), 200)
    }
  } catch {
    // canvas-confetti not available — silent no-op (progressive enhancement)
  }
}
